<span class="line"><span style="color:#ABB2BF;">    cout</span><span style="color:#C678DD;">&lt;&lt;</span><span style="color:#ABB2BF;">ans</span><span style="color:#C678DD;">&lt;&lt;</span><span style="color:#ABB2BF;">endl;</span></span>
